#include <stdio.h>
#include <stdint.h>

static int popcountll(uint64_t x) {
    return __builtin_popcountll(x);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t A, B;
        scanf("%llu %llu", &A, &B);
        if (A == B) {
            printf("0\n");
            continue;
        }
        if (B == 0) {
            printf("-1\n");
            continue;
        }
        if (B == 1) {
            printf(A == 0 ? "1\n" : "-1\n");
            continue;
        }
        int aa = popcountll(A);
        int bb = popcountll(B - 1);
        if (aa > bb) {
            printf("-1\n");
        } else {
            printf("%d\n", bb - aa + 1);
        }
    }
    return 0;
}

