import java.io.*;
import java.util.*;

public class Main {
    private static int popcount(long x) {
        return Long.bitCount(x);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long A = Long.parseUnsignedLong(st.nextToken());
            long B = Long.parseUnsignedLong(st.nextToken());
            if (A == B) {
                out.append(0).append('\n');
                continue;
            }
            if (B == 0) {
                out.append(-1).append('\n');
                continue;
            }
            if (B == 1) {
                out.append(A == 0 ? 1 : -1).append('\n');
                continue;
            }
            int aa = popcount(A);
            int bb = popcount(B - 1);
            if (aa > bb) out.append(-1).append('\n');
            else out.append(bb - aa + 1).append('\n');
        }
        System.out.print(out.toString());
    }
}

