import sys

def popcount(x: int) -> int:
    return bin(x).count('1')

def solve_one(A: int, B: int) -> int:
    if A == B:
        return 0
    if B == 0:
        return -1
    if B == 1:
        return 1 if A == 0 else -1
    aa = popcount(A)
    bb = popcount(B - 1)
    if aa > bb:
        return -1
    return bb - aa + 1

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    t = int(data[0])
    res = []
    idx = 1
    for _ in range(t):
        A = int(data[idx]); B = int(data[idx+1])
        res.append(str(solve_one(A, B)))
        idx += 2
    sys.stdout.write('\n'.join(res))

if __name__ == "__main__":
    main()

