const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(input[pos++]);
let out = [];
function popcountBigInt(x) {
  let n = x;
  let cnt = 0n;
  while (n) {
    cnt += n & 1n;
    n >>= 1n;
  }
  return Number(cnt);
}
for (let i = 0; i < T; i++) {
  const A = BigInt(input[pos++]);
  const B = BigInt(input[pos++]);
  if (A === B) {
    out.push('0');
    continue;
  }
  if (B === 0n) {
    out.push('-1');
    continue;
  }
  if (B === 1n) {
    out.push(A === 0n ? '1' : '-1');
    continue;
  }
  const aa = popcountBigInt(A);
  const bb = popcountBigInt(B - 1n);
  if (aa > bb) out.push('-1');
  else out.push(String(bb - aa + 1));
}
